import { db } from "@/database/db"
import { orders } from "@/database/schema"
import { eq, desc } from "drizzle-orm"

export async function getOrders(page: number, status?: string) {
  const limit = 20
  const offset = (page - 1) * limit

  let query = db.select().from(orders).orderBy(desc(orders.createdAt)).limit(limit).offset(offset)

  if (status) {
    query = query.where(eq(orders.status, status)) as typeof query
  }

  return query
}
